import React, { useState, useEffect } from "react";
import api from "../api/api"; // Usamos nuestra instancia configurada de Axios
import { useNavigate } from "react-router-dom";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    _id: null, // Cambiado de id a _id para MongoDB
    Nombre: "", // Usamos Mayúsculas para coincidir con el Modelo
    Descripcion: "",
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  // 📄 CONFIGURACIÓN DE PAGINACIÓN
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // ✅ OBTENER DATOS DESDE MONGODB ATLAS
  const obtenerCategorias = async () => {
    try {
      setLoading(true);
      const res = await api.get("/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({
      ...categoriaActual,
      [e.target.name]: e.target.value,
    });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ _id: null, Nombre: "", Descripcion: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (cat) => {
    setCategoriaActual(cat);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await api.put(`/categorias/${categoriaActual._id}`, categoriaActual);
      } else {
        await api.post("/categorias", categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      const errorMsg = error.response?.data?.mensaje || "Error al procesar la solicitud";
      alert("❌ " + errorMsg);
    }
  };

  const eliminarCategoria = async (id) => {
    if (!window.confirm("¿Estás seguro de eliminar esta categoría?")) return;
    try {
      await api.delete(`/categorias/${id}`);
      obtenerCategorias();
    } catch (error) {
      const errorMsg = error.response?.data?.mensaje || "No se pudo eliminar";
      alert("⚠️ Error: " + errorMsg);
    }
  };

  // 🔎 LÓGICA DE FILTRADO
  const categoriasFiltradas = categorias.filter((c) =>
    c.Nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  // 📄 CÁLCULO DE PAGINACIÓN
  const totalPaginas = Math.ceil(categoriasFiltradas.length / categoriasPorPagina);
  const inicio = (paginaActual - 1) * categoriasPorPagina;
  const categoriasPaginadas = categoriasFiltradas.slice(inicio, inicio + categoriasPorPagina);

  return (
    <div className="container-fluid py-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-dark m-0">📁 Categorías</h2>
        <button className="btn btn-primary shadow-sm" onClick={abrirModalAgregar}>
          + Nueva Categoría
        </button>
      </div>

      {/* BARRA DE BÚSQUEDA */}
      <div className="card border-0 shadow-sm mb-4">
        <div className="card-body">
          <input
            className="form-control form-control-lg border-0 bg-light"
            placeholder="🔍 Buscar categoría..."
            value={busqueda}
            onChange={(e) => {
              setBusqueda(e.target.value);
              setPaginaActual(1);
            }}
          />
        </div>
      </div>

      {loading ? (
        <div className="text-center mt-5"><div className="spinner-border text-primary"></div></div>
      ) : (
        <>
          <div className="row">
            {categoriasPaginadas.map((cat) => (
              <div key={cat._id} className="col-md-4 mb-4">
                <div 
                  className="card shadow-sm h-100 border-0" 
                  style={{ transition: "0.3s", borderRadius: "15px" }}
                >
                  <div className="card-body p-4">
                    <h5 className="fw-bold text-primary mb-2">{cat.Nombre}</h5>
                    <p className="text-muted small mb-4" style={{ minHeight: "40px" }}>
                      {cat.Descripcion || "Sin descripción disponible."}
                    </p>
                    
                    <div className="d-flex gap-2">
                      <button
                        className="btn btn-light btn-sm flex-fill fw-bold"
                        onClick={() => abrirModalEditar(cat)}
                      >
                        ✏️ Editar
                      </button>
                      <button
                        className="btn btn-outline-danger btn-sm flex-fill fw-bold"
                        onClick={() => eliminarCategoria(cat._id)}
                      >
                        🗑️ Borrar
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {categoriasFiltradas.length === 0 && (
            <div className="text-center py-5">
              <p className="text-muted">No se encontraron categorías.</p>
            </div>
          )}

          {/* PAGINACIÓN */}
          {totalPaginas > 1 && (
            <nav className="mt-4">
              <ul className="pagination justify-content-center">
                {[...Array(totalPaginas)].map((_, i) => (
                  <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
                    <button className="page-link" onClick={() => setPaginaActual(i + 1)}>{i + 1}</button>
                  </li>
                ))}
              </ul>
            </nav>
          )}
        </>
      )}

      {/* MODAL */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.5)", backdropFilter: "blur(4px)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg">
              <div className="modal-header">
                <h5 className="fw-bold">{modoEdicion ? "Actualizar" : "Crear"} Categoría</h5>
                <button type="button" className="btn-close" onClick={() => setShowModal(false)}></button>
              </div>
              <form onSubmit={guardarCategoria}>
                <div className="modal-body p-4">
                  <div className="mb-3">
                    <label className="form-label fw-bold">Nombre</label>
                    <input
                      name="Nombre"
                      className="form-control"
                      value={categoriaActual.Nombre}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label fw-bold">Descripción</label>
                    <textarea
                      name="Descripcion"
                      className="form-control"
                      rows="3"
                      value={categoriaActual.Descripcion}
                      onChange={handleChange}
                    />
                  </div>
                </div>
                <div className="modal-footer border-0">
                  <button type="button" className="btn btn-light" onClick={() => setShowModal(false)}>Cancelar</button>
                  <button type="submit" className="btn btn-primary px-4">Guardar</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
